#!/usr/bin/env bash
# Generated by pivota-spec init-dev-server
# Catalog entry: agent-synthesized
# Generator version: init-dev-server@1
#
# Edits ABOVE the END PIVOTA PREAMBLE marker are reset on regen.
# Edits BELOW the marker are preserved on regen.
#
# Why these choices (decision-trace; do not delete):
#   - `set -euo pipefail` not just `-e` — RESEARCH.md Pitfall 4 (silent pipe failures).
#   - `sha256sum` for lockfile hashing — RESEARCH.md "Don't hand-roll" (universal
#     coreutils, no extra dep vs blake3 / git hash-object / md5sum).
#   - Backoff 1s / 2s / 4s — Claude's Discretion per CONTEXT.md (small base, predictable).
#   - Log destination `/tmp/pivota-dev.log` — Open Question #4 resolved (always
#     writable inside Daytona sandboxes; matches existing convention).
#   - Lockfile-sentinel skip combined with INSTALL_PRESENCE_CHECK — RESEARCH.md
#     Pitfall 6 (sentinel survives reboots but install output dirs may not on
#     fresh tmpfs; never skip on a clean directory).
#   - Retry exits with INNER command's last exit code (not a fixed 1) so callers
#     can disambiguate failures from the wrapper.
#   - Agent-synthesized (zero catalog matches): PHP/Apache CRM + Spring Boot API.
#     Docker daemon is absent in Daytona K8s sandboxes — services are launched directly.
#   - Spring Boot API binds 0.0.0.0 via SERVER_ADDRESS env var (catalog java-spring.md).
#   - PHP CRM uses php -S built-in dev server on 0.0.0.0:8081 (no Apache required).
#   - Multi-process: trap+wait-n per RESEARCH.md Pattern 3 (no concurrently/pm2/supervisord).
#   - JDK install snippet copied from java-spring catalog entry (project_preview_service.rs:343-348).
#   - Flyway migrations run automatically on Spring Boot startup (spring.flyway.enabled=true).
#   - composer install for PHP CRM dependencies.
#   - DATABASE_URL is platform-injected; never shadowed (D-11.3 injection-safe .env seeding).

set -euo pipefail

# === Bash version guard (RESEARCH.md Pitfall 8) ===
# `wait -n` (used by the multi-process variant) requires bash >= 4.3.
# Fail fast with a clear message; do not silently degrade.
if (( BASH_VERSINFO[0] < 4 )) || { (( BASH_VERSINFO[0] == 4 )) && (( BASH_VERSINFO[1] < 3 )); }; then
  echo "[pivota] bash 4.3+ required for 'wait -n'; found ${BASH_VERSION}" >&2
  exit 127
fi

# === D-11.4: tee stdout/stderr to /tmp/pivota-dev.log AND pass through ===
mkdir -p /tmp
exec > >(tee -a /tmp/pivota-dev.log) 2>&1
echo "[pivota] $(date -Iseconds) start-dev.sh begin (catalog: agent-synthesized)"

# === D-11.1 + D-11.2: per-stack 0.0.0.0 binding + host allowlist relaxation ===
# Spring Boot: SERVER_ADDRESS forces 0.0.0.0 binding (relaxed-binding from server.address).
# CITED: docs.spring.io/spring-boot/.../application-properties — server.address env equivalent.
# Spring binds by IP, not by Host header — no host-allowlist check to suppress.
export SERVER_ADDRESS=0.0.0.0
# PHP built-in server: binding is passed as CLI arg (-S 0.0.0.0:8081) — no env var lever.

# === D-11.3: .env.example -> .env seed (platform-injection-safe) ===
# Seed .env from .env.example for first boot, but NEVER let an .env.example
# placeholder shadow a variable the platform already injected into the sandbox
# environment. Any KEY already set in the environment is dropped from the copy.
if [[ ! -f .env && -f .env.example ]]; then
  echo "[pivota] seeding .env from .env.example (preserving platform-injected vars)"
  while IFS= read -r line || [[ -n "$line" ]]; do
    trimmed="${line#"${line%%[![:space:]]*}"}"   # left-trim for the test only
    if [[ "$trimmed" == \#* || -z "$trimmed" || "$trimmed" != *"="* ]]; then
      printf '%s\n' "$line"; continue            # keep comments / blanks / non-assignments
    fi
    key="${trimmed#export }"; key="${key%%=*}"; key="${key//[[:space:]]/}"
    if [[ -n "${!key+x}" ]]; then
      printf '# [pivota] %s omitted — provided by platform environment\n' "$key"
    else
      printf '%s\n' "$line"
    fi
  done < .env.example > .env
fi

# === Pre-exec snippet: JDK install (java-spring catalog, project_preview_service.rs:343-348) ===
# Daytona base snapshot does NOT ship OpenJDK (RESEARCH.md Pitfall 7).
# This snippet is idempotent (checks command -v java before installing).
(command -v java >/dev/null 2>&1 \
    || (echo "[pivota] installing OpenJDK 21 (one-time, ~30s)" \
        && sudo apt-get update -qq \
        && sudo DEBIAN_FRONTEND=noninteractive apt-get install -y -qq openjdk-21-jdk-headless)) \
    && export JAVA_HOME=$(readlink -f $(command -v java) 2>/dev/null | sed -E "s%/bin/java$%%") \
    && echo "[pivota] JAVA_HOME=$JAVA_HOME"

# Ensure JDK bin is on PATH for the rest of the wrapper (mvn needs `java`).
export PATH="$JAVA_HOME/bin:$PATH"

# === Pre-exec snippet: mvn install (ensure maven is available) ===
if ! command -v mvn >/dev/null 2>&1; then
  echo "[pivota] installing Maven (one-time, ~15s)"
  sudo apt-get update -qq
  sudo DEBIAN_FRONTEND=noninteractive apt-get install -y -qq maven
fi

# === Pre-exec snippet: PHP + Composer availability check ===
if ! command -v php >/dev/null 2>&1; then
  echo "[pivota] installing PHP 8.2 (one-time, ~30s)"
  sudo apt-get update -qq
  sudo DEBIAN_FRONTEND=noninteractive apt-get install -y -qq php8.2-cli php8.2-pdo php8.2-pgsql php8.2-mbstring php8.2-xml php8.2-curl
fi
if ! command -v composer >/dev/null 2>&1; then
  echo "[pivota] installing Composer (one-time)"
  curl -sS https://getcomposer.org/installer | php -- --install-dir=/usr/local/bin --filename=composer
fi

# === D-12: idempotent install via lockfile hash + presence check ===
SENTINEL="/tmp/pivota-setup-sentinel"
LOCK_FILE_PATH="backend/pom.xml"
INSTALL_PRESENCE_CHECK="backend/target"
INSTALL_CMD='cd backend && mvn dependency:resolve -B -q && cd ..'

# PHP lockfile sentinel (separate sentinel file)
PHP_SENTINEL="/tmp/pivota-php-setup-sentinel"
PHP_LOCK_FILE="crm/composer.lock"
PHP_INSTALL_CMD='cd crm && composer install --no-interaction --prefer-dist && cd ..'
PHP_PRESENCE_CHECK="crm/vendor"

run_install() {
  echo "[pivota] running Java install: $INSTALL_CMD"
  bash -c "$INSTALL_CMD"
}

run_php_install() {
  echo "[pivota] running PHP install: $PHP_INSTALL_CMD"
  bash -c "$PHP_INSTALL_CMD"
}

# Java dependency install
if [[ -n "$LOCK_FILE_PATH" && -f "$LOCK_FILE_PATH" ]]; then
  CURRENT_HASH=$(sha256sum "$LOCK_FILE_PATH" | cut -d' ' -f1)
  PREVIOUS_HASH=$(cat "$SENTINEL" 2>/dev/null || echo "")
  PRESENCE_OK=1
  if [[ -n "$INSTALL_PRESENCE_CHECK" && ! -e "$INSTALL_PRESENCE_CHECK" ]]; then
    PRESENCE_OK=0
  fi
  if [[ "$CURRENT_HASH" == "$PREVIOUS_HASH" && "$PRESENCE_OK" == "1" ]]; then
    echo "[pivota] Java lockfile unchanged AND install output present; skipping install"
  else
    if [[ "$PRESENCE_OK" == "0" ]]; then
      echo "[pivota] Java install output ($INSTALL_PRESENCE_CHECK) missing; install required"
    else
      echo "[pivota] Java lockfile changed (or first boot); install required"
    fi
    run_install
    echo "$CURRENT_HASH" > "$SENTINEL"
  fi
fi

# PHP Composer install
if [[ -f "$PHP_LOCK_FILE" ]]; then
  PHP_CURRENT_HASH=$(sha256sum "$PHP_LOCK_FILE" | cut -d' ' -f1)
  PHP_PREVIOUS_HASH=$(cat "$PHP_SENTINEL" 2>/dev/null || echo "")
  PHP_PRESENCE_OK=1
  if [[ ! -e "$PHP_PRESENCE_CHECK" ]]; then
    PHP_PRESENCE_OK=0
  fi
  if [[ "$PHP_CURRENT_HASH" == "$PHP_PREVIOUS_HASH" && "$PHP_PRESENCE_OK" == "1" ]]; then
    echo "[pivota] PHP lockfile unchanged AND vendor present; skipping composer install"
  else
    if [[ "$PHP_PRESENCE_OK" == "0" ]]; then
      echo "[pivota] PHP vendor dir missing; composer install required"
    else
      echo "[pivota] PHP lockfile changed (or first boot); composer install required"
    fi
    run_php_install
    echo "$PHP_CURRENT_HASH" > "$PHP_SENTINEL"
  fi
fi

# === Also install COB theme Composer deps if present ===
if [[ -f "crm/data/Themes/COB/composer.json" && ! -d "crm/data/Themes/COB/vendor" ]]; then
  echo "[pivota] installing COB theme Composer deps"
  (cd crm/data/Themes/COB && composer install --no-interaction --prefer-dist)
fi

# === Seed CRM site_config.php from docker template if missing ===
if [[ ! -f "crm/data/site_config.php" && -f "infra/site_config.docker.php" ]]; then
  echo "[pivota] seeding crm/data/site_config.php from infra/site_config.docker.php"
  cp infra/site_config.docker.php crm/data/site_config.php
fi

# === Multi-process supervision (RESEARCH.md Pattern 3) ===
# Defense-in-depth bash version guard — also enforced by preamble above.
if (( BASH_VERSINFO[0] < 4 )) || { (( BASH_VERSINFO[0] == 4 )) && (( BASH_VERSINFO[1] < 3 )); }; then
  echo "[pivota] multi-process block requires bash 4.3+ for wait -n; found ${BASH_VERSION}" >&2
  exit 127
fi

shutdown() {
  echo "[pivota] shutting down children"
  kill -TERM "${PIDS[@]}" 2>/dev/null || true
  # Brief grace, then SIGKILL stragglers (RESEARCH.md Pitfall 3: npm SIGTERM)
  sleep 2
  kill -KILL "${PIDS[@]}" 2>/dev/null || true
  wait
}
trap shutdown SIGTERM SIGINT EXIT

declare -a PIDS=()

# --- Process 1: Spring Boot API (port 8080) ---
# Flyway migrations run automatically on startup (spring.flyway.enabled=true in application.yml).
# DATABASE_URL is platform-injected; application.yml reads ${DATABASE_URL:jdbc:postgresql://...}.
# SERVER_ADDRESS=0.0.0.0 set above forces 0.0.0.0 binding.
(
  cd backend \
    && bash -c 'mvn spring-boot:run -Dspring-boot.run.jvmArguments="-Dserver.address=0.0.0.0"'
) 2>&1 | sed 's/^/[api] /' &
PIDS+=($!)

# --- Process 2: PHP CRM built-in dev server (port 8081) ---
# Uses PHP's built-in web server — no Apache daemon required.
# SITE_HOME points at crm/data where site_config.php lives.
# Note: PHP built-in server is for development only; single-threaded.
(
  export SITE_HOME="$(pwd)/crm/data" \
    && cd crm \
    && bash -c 'php -S 0.0.0.0:8081 -t public'
) 2>&1 | sed 's/^/[crm] /' &
PIDS+=($!)

# Wait for ANY child to exit; if one dies, the trap tears down siblings.
wait -n
EXIT_CODE=$?
shutdown
exit "$EXIT_CODE"

